import Seo from '@/component/seo'
import avatarImgUrl from '@/resource/image/avatar.jpg'
import { Link, graphql } from 'gatsby'
import React from 'react'
import classes from './index.module.styl'

export interface HomePageProps {
  data: {
    site: {
      siteMetadata: {
        author: {
          name: string
          motto: string
          github: string
          rss: string
        }
      }
    }
  }
}

export default function HomePage(
  props: HomePageProps,
): React.ReactElement | null {
  const {
    site: {
      siteMetadata: { author },
    },
  } = props.data

  return (
    <div className={classes.container}>
      <Seo title="首页" description="光和尘的个人站点" />
      <div className={classes.main}>
        <header>
          <span className={classes.avatar}>
            <img alt="avatar" src={avatarImgUrl} />
          </span>
          <h1 className={classes.author}>{author.name}</h1>
          <p className={classes.motto}>{author.motto}</p>
        </header>
        <div className={classes.nav}>
          {routes.map((route, index) => (
            <React.Fragment key={route.url}>
              {index > 0 && <span className={classes.tileSplit} />}
              <Link className={classes.tile} to={route.url}>
                <span>{route.title}</span>
              </Link>
            </React.Fragment>
          ))}
        </div>
      </div>
    </div>
  )
}

const routes = [
  {
    title: 'post',
    url: '/posts',
  },
  {
    title: 'essay',
    url: '/essays',
  },
]

export const query = void graphql`
query HomePage {
  site {
    siteMetadata {
      author {
        name
        motto
        github
        rss
      }
      copyright {
        date
      }
    }
  }
}
`
